  ('aboriginal-6e11b43e-moex-00332', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列何者屬於行政法之成文法源？', '["地方自治法規", "行政法院判決", "行政法之原理原則", "行政慣例"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00333', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '行政處分之內容對任何人均屬不能實現者，此屬於下列何種行政法原則？', '["法律保留原則", "授權明確性原則", "期待可能性原則", "信賴保護原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00334', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依司法院解釋意旨，關於公法與私法關係之敘述，下列何者錯誤？', '["未辦理繼承登記土地之合法使用人，對財政部國有財產署所為之土地公開標售，依土地法規定 請求同意優先購買，性質上屬私法關係", "人民依國有財產法規定，請求財政部國有財產署同意讓售國有非公用財產類不動產，性質上屬 私法關係", "人民依國有林地濫墾地補辦清理作業要點，請求行政機關同意出租國有林地，性質上屬公法 關係", "人民依住宅法，請求行政機關同意出租社會住宅，性質上屬公法關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00335', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '行政機關之設置，下列何者僅需以命令定之即可？', '["獨立機關", "二級機關", "三級機關", "分署或分局"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00336', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依地方制度法規定，有關自治法規之名稱，下列敘述何者正確？', '["經地方立法機關通過，並由各該行政機關公布者，稱自治規章", "由地方行政機關訂定，並發布或下達者，稱自治條例", "經地方立法機關通過，並由各該行政機關公布者，稱自律規則", "由地方行政機關訂定，並發布或下達者，稱自治規則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00337', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政機關管轄權之敘述，下列何者正確？', '["在法律規定有中央主管機關與地方主管機關之層級管轄情形，地方自治團體可於自治條例中決 定其執行機關", "行政機關之管轄，須為管轄恆定，並無例外", "行政機關之管轄權，得依機關首長之指令變更之", "自治監督機關代行處理地方行政機關之權限，並不屬於管轄恆定原則之例外"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00338', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依據公務員懲戒法，關於停止職務之規定，下列敘述何者錯誤？', '["公務員依刑事訴訟程序被羈押者，其職務當然停止", "懲戒法庭對於移送之懲戒案件，認為情節重大，有先行停止職務之必要者，得裁定先行停止被 付懲戒人之職務", "對公務員停止職務應依懲戒法庭之裁定，主管機關不得依職權為之", "公務員在停職中所為之職務上行為，不生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00339', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依公務人員考績法之規定，關於公務人員平時考核及專案考績，下列敘述何者正確？', '["平時考核懲處種類包括申誡、罰款、記過、記大過", "平時考核獎懲得互相抵銷", "專案考績得與平時考核功過相抵銷", "專案考績一次記三大過者免職"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00340', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於公務人員申訴、再申訴程序之敘述，依實務見解，下列何者錯誤？', '["公務人員保障法第 77 條之規定並未限制公務人員認其權利受違法侵害或有主張其權利之必要 時，得依法提起相應之行政訴訟，請求救濟", "公務人員欲循行政訴訟法請求救濟時，仍應符合相關行政訴訟類型之法定要件", "申訴之提起，應於該管理措施或有關工作條件之處置到達之次日起 30日內，向原服務機關 提出", "服務機關對申訴事件，應於收受申訴書之次日起30日內，就請求事項詳備理由函復，為有效保 障公務人員之權益該期間不得延長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00341', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政命令，下列敘述何者正確？', '["行政機關訂定法規命令，得依職權舉行聽證", "基於主權在民原則，若人民提議訂定法規命令，行政機關即負有訂定法規命令之義務", "就一事項究應以法規命令或行政規則訂定之，行政機關得自由選擇", "經聽證訂定之法規命令，其行政救濟程序，免除訴願及其先行程序"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL)
